import React from 'react';
import '../Styling/CiteShare.css';
import { emitToast } from './Toast';

function formatAPA({ title, author, date, url }) {
    // Very small, opinionated APA-ish formatter for the site
    const authorStr = author || 'UJLP';
    const year = (date && new Date(date).getFullYear()) || new Date().getFullYear();
    return `${authorStr} (${year}). ${title}. Retrieved from ${url}`;
}

function formatMLA({ title, author, date, url }) {
    const authorStr = author || 'UJLP';
    const year = (date && new Date(date).getFullYear()) || new Date().getFullYear();
    return `${authorStr}. "${title}." ${year}. ${url}`;
}

function formatBibTeX({ title, author, date, url, id = 'ujlp' }) {
    const year = (date && new Date(date).getFullYear()) || new Date().getFullYear();
    // Avoid backslash-u sequences by not including backslashes in template; provide a simple bibtex entry
    return `@misc{${id},\n  author = {${author}},\n  title = {${title}},\n  year = {${year}},\n  howpublished = {${url}}\n}`;
}

function copyToClipboard(text) {
    if (navigator.clipboard && navigator.clipboard.writeText) {
        return navigator.clipboard.writeText(text);
    }
    return new Promise((res, rej) => {
        try {
            const ta = document.createElement('textarea');
            ta.value = text;
            document.body.appendChild(ta);
            ta.select();
            document.execCommand('copy');
            document.body.removeChild(ta);
            res();
        } catch (e) {
            rej(e);
        }
    });
}

function CiteShare({ title, author, date, url }) {
    const meta = { title, author, date, url };

    const onCopy = async (format) => {
        let text;
        if (format === 'apa') text = formatAPA(meta);
        else if (format === 'mla') text = formatMLA(meta);
        else if (format === 'bib') text = formatBibTeX(meta);
        else text = url;

        try {
            await copyToClipboard(text);
            emitToast('Copied to clipboard');
        } catch (e) {
            emitToast('Copy failed — please copy manually');
            console.error(e);
        }
    };

    const onShare = (platform) => {
        if (platform === 'copy') {
            onCopy('link');
        }
    };

    return (
        <div className="cite-share cite-box" role="region" aria-label="Citation and sharing tools">
            <div className="cite-header">
                <strong>Cite this article</strong>
            </div>
            <div className="cite-actions">
                <button onClick={() => onCopy('apa')} className="cite-btn orange">Copy APA</button>
                <button onClick={() => onCopy('mla')} className="cite-btn orange">Copy MLA</button>
                <button onClick={() => onCopy('bib')} className="cite-btn orange">Copy BibTeX</button>
                <button onClick={() => onShare('copy')} className="cite-btn orange">Copy Link</button>
            </div>
        </div>
    );
}

export default CiteShare;
